script.text:
      /* <flatten type="Javascript"> */
function init$EmployeeGrid(g, v) {
  if (!g._name) {
    var a1 = v.split(','), a2 = [];
    for (var i = 0; i < a1.length; i++) {
      a2[i] = a1[i].split(':');
    }
    g._name = a2;
  }
  set$FilterMemvar(g);
  g.add_onResponseComplete(on$EmployeeGrid$ResponseComplete);
  g.add_commandEvent(on$EmployeeGrid$ExecuteCommand);
}
function dispose$EmployeeGrid(g) {
  try {g.remove_commandEvent(on$EmployeeGrid$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$EmployeeGrid$ResponseComplete);} catch (ex) {}
}
function on$EmployeeGrid$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, v = e.type.Value, view = g._view;
  switch (action) {
    case 'RowColChange':
      var employeeID = g._getItemValue(g._activeRow, 1);
      if ((v.Active.Row != v.Previous.Row) && (employeeID != '')) {
        view._currentID = employeeID;
        show$EmployeeInformation(g);
      }
      break;
    case 'AfterRemoveRow':
      if (g._rowCount == 0) g._view.showTabControl('');
      break;
    case 'BeforeFormLoad':
      e.type.Value.set_vars([{Name: 'b', Type: 'String', Value: view._activeDept}]);
      break;
    case 'ImportData':
      show$Form(g, 'hrPIGeneralInformationImport');
      break;
    case 'CopyEmployee':
      if (g._activeRow == -1) return;
      g._employeeID = $func.trim(g._getItemValue(g._activeRow, g._getColumnOrder('ma_nv')));
      show$Form$Edit(g, 'hrPIGeneralInformationCopyEmployee');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
function on$EmployeeGrid$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    case 'FullImage':
      g._fullImageKey = result[0].Value;
      break;
    default:
      break;
  }
}
function refresh$EmployeeViewPanel(g) {
  var view = g._view;
  view.showTabControl('');
  if (g._hideViewPanel) {
    view.deptTree.unSelect();
    view._activeDept = view._prevTab = view._currentID = '';
    g._hideViewPanel = false;
  }
}
function show$EmployeeInformation(g) {
  var view = g._view, stt_rec = g._getItemValue(g._activeRow, g._getColumnOrder('stt_rec'));
  g.request(g, 'FullImage', 'FullImage', [['stt_rec', 'String', stt_rec]]);

  if (view._controller) {
    if (view._type) view.showGridDetail();
    else window.setTimeout(function() {view.showViewPanel();}, 100);
  }
}
function set$ViewPanelEmployeeID(f) {
  if (f._action == 'New') {
    var g = $find(f.get_id().split('_MainReport')[0] + '_MainReport');
    f.setItemValue('stt_rec', g._view._currentID);
  }
}
function show$ViewPanelEmployeeID(f) {
  var g = $find(f.get_id().split('_MainReport')[0] + '_MainReport');
  g._view.scatterMemvar(f);
}
function set$FilterMemvar(g) {
  var view = g._view;
  g._stringValue = []; g._dateTimeValue = [];
  var f1 = view._stringFields, f2 = view._dateTimeFields;
  for (var i = 1; i < f1.length; i++) g._stringValue[i] = get$FilterValue($func.trim(f1[i]));
  for (var i = 0; i < f2.length; i++) g._dateTimeValue[i] = null;
}
function get$FilterValue(field) {
  switch (field) {
    case 'status':
    case 'nv_cd_yn':
      return '1';
    default:
      return '';
  }
}
function show$Form(g, c) {g._authorize == 1 ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess")) : $message.show(g._denyMessage);}
function show$Form$Edit(g, c) {g._authorizeEdit == 1 ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess")) : $message.show(g._denyMessage);}
/* </flatten> */
